/**
 * Tauri tray event listeners.
 *
 * Rust emits these via `app.emit(...)` from `src/main.rs` whenever the
 * user clicks a tray menu item:
 *
 *   tray:focus-agent   — payload: agent id (string)
 *   tray:spawn-agent   — payload: ()
 *   tray:open-settings — payload: ()
 *   tray:show-about    — payload: ()
 *   tray:check-update  — payload: ()
 *
 * The frontend dispatches these to lightweight pub/sub callbacks so
 * any pane / dialog can react. Web mode: no-op subscribe.
 */

import { isTauri } from './index.js';
import { checkForUpdates } from './updater.js';

export type TauriEvent =
  | 'tray:focus-agent'
  | 'tray:spawn-agent'
  | 'tray:open-settings'
  | 'tray:show-about'
  | 'tray:check-update';

type Listener<T> = (payload: T) => void;
type ListenerMap = {
  'tray:focus-agent': Set<Listener<string>>;
  'tray:spawn-agent': Set<Listener<void>>;
  'tray:open-settings': Set<Listener<void>>;
  'tray:show-about': Set<Listener<void>>;
  'tray:check-update': Set<Listener<void>>;
};

const listeners: ListenerMap = {
  'tray:focus-agent': new Set(),
  'tray:spawn-agent': new Set(),
  'tray:open-settings': new Set(),
  'tray:show-about': new Set(),
  'tray:check-update': new Set(),
};

let wired = false;

/**
 * Wire Tauri's event system into our local pub/sub. Idempotent. Web
 * mode: no-op.
 */
export async function wireTrayEvents(): Promise<void> {
  if (!isTauri() || wired) return;
  wired = true;

  let listen: typeof import('@tauri-apps/api/event').listen;
  try {
    ({ listen } = await import('@tauri-apps/api/event'));
  } catch (err) {
    console.warn('[tauri-bridge] event API unavailable', err);
    wired = false;
    return;
  }

  await listen<string>('tray:focus-agent', (event) => {
    listeners['tray:focus-agent'].forEach((cb) => cb(event.payload));
  });
  await listen<void>('tray:spawn-agent', () => {
    listeners['tray:spawn-agent'].forEach((cb) => cb());
  });
  await listen<void>('tray:open-settings', () => {
    listeners['tray:open-settings'].forEach((cb) => cb());
  });
  await listen<void>('tray:show-about', () => {
    listeners['tray:show-about'].forEach((cb) => cb());
  });
  await listen<void>('tray:check-update', () => {
    listeners['tray:check-update'].forEach((cb) => cb());
    // The "Check for Updates..." item should also kick the actual
    // check rather than relying on a UI subscriber to do it.
    void checkForUpdates({ silentIfNone: false });
  });
}

/** Subscribe a callback to a tray event. Returns an unsubscribe fn. */
export function onTrayEvent(event: 'tray:focus-agent', cb: Listener<string>): () => void;
export function onTrayEvent(
  event: 'tray:spawn-agent' | 'tray:open-settings' | 'tray:show-about' | 'tray:check-update',
  cb: Listener<void>,
): () => void;
// eslint-disable-next-line @typescript-eslint/no-explicit-any
export function onTrayEvent(event: TauriEvent, cb: any): () => void {
  const set = listeners[event] as Set<Listener<unknown>>;
  set.add(cb);
  return () => {
    set.delete(cb);
  };
}
